-- Create "email_verification_tokens" table
CREATE TABLE "email_verification_tokens" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "user_id" bigint NOT NULL,
  "token_hash" character varying NOT NULL,
  "token_version" character varying NOT NULL DEFAULT 'v1',
  "expires_at" timestamptz NOT NULL,
  "used_at" timestamptz NULL,
  PRIMARY KEY ("id")
);
-- Create index "emailverificationtoken_token_hash" to table: "email_verification_tokens"
CREATE UNIQUE INDEX "emailverificationtoken_token_hash" ON "email_verification_tokens" ("token_hash");
-- Create index "emailverificationtoken_user_id_created_at" to table: "email_verification_tokens"
CREATE INDEX "emailverificationtoken_user_id_created_at" ON "email_verification_tokens" ("user_id", "created_at");
-- Create index "emailverificationtoken_expires_at" to table: "email_verification_tokens"
CREATE INDEX "emailverificationtoken_expires_at" ON "email_verification_tokens" ("expires_at");
-- Create index "emailverificationtoken_used_at" to table: "email_verification_tokens"
CREATE INDEX "emailverificationtoken_used_at" ON "email_verification_tokens" ("used_at");
